(window.webpackJsonp=window.webpackJsonp||[]).push([[260],{887:function(r,n){r.exports="\x3c!-- \r\ntitle: 40-网络编程\r\nsort: \r\n--\x3e \r\n# 网络编程\r\n\r\n## TCP\r\n\r\n### 客户端\r\n\r\n基于tcp连接的Socket\r\n\r\n```python\r\nimport socket\r\n\r\n# 创建socket，使用IPv4，面向流的TCP协议\r\ns = socket.socket(socket.AF_INET, socket.SOCK_STREAM)\r\ns.connect(('www.sina.cn', 80))\r\n\r\ns.send(b'GET / HTTP/1.1\\r\\nHost: www.sina.com.cn\\r\\nConnection: close\\r\\n\\r\\n')\r\n\r\n# 接收数据:\r\nbuffer = []\r\nwhile True:\r\n    # 每次最多接收1k字节:\r\n    d = s.recv(1024)\r\n    if d:\r\n        buffer.append(d)\r\n    else:\r\n        break\r\ndata = b''.join(buffer)\t\t# 将列表变成字符串\r\ns.close()\r\nheader, html = data.split(b'\\r\\n\\r\\n', 1)\t# 将header与html凭借换行符分开\r\nprint(header.decode('utf-8'))\r\n# 把接收的数据写入文件:\r\nwith open('sina.html', 'wb') as f:\r\n    f.write(html)\r\n```\r\n\r\n### 服务器\r\n\r\n#### 服务器端\r\n\r\n```python\r\nimport socket\r\nimport threading\r\nimport time\r\n\r\n\r\ndef tcplink(sock, addr):    # 发送数据包\r\n    print('connection from %s:%s' % addr)\r\n    sock.send(b'WELCOME')\r\n    while True:\r\n        r = sock.recv(1024) # 接收信息\r\n        time.sleep(1)\r\n        if r == 'exit' or r.decode('utf-8') == 'exit':\r\n            break\r\n        sock.send(b'HELLO,%s' % r)  # 发送信息\r\n    sock.close()\r\n    print('connection from %s:%s closed' % addr)\r\n\r\n\r\ns = socket.socket(socket.AF_INET, socket.SOCK_STREAM)\r\ns.bind(('127.0.0.1', 9999))\r\ns.listen(5) # 最多5个连接\r\nwhile True:\r\n    sock, addr = s.accept() # 接受一个连接\r\n    t = threading.Thread(target=tcplink, args=(sock, addr)) # 新建线程\r\n    t.start()\r\n```\r\n\r\n#### 用户端\r\n\r\n```python\r\nimport socket \r\n\r\ns1=socket.socket(socket.AF_INET,socket.SOCK_STREAM)\r\ns1.connect(('127.0.0.1',9999)) \r\n\r\nfor i in [b'lily',b'tom',b'jim']:\r\n\ts1.send(i)  # 发送信息\r\n\twhile True: \r\n\t\tr = s1.recv(1024)\r\n\t\tif r: \r\n\t\t\tprint(r.decode('utf-8'))\r\n\t\telse: \r\n\t\t\tbreak \r\ns1.send(b'exit')\r\ns1.close()\r\n```\r\n\r\n## UDP编程\r\n\r\n```python\r\n# 服务器\r\ns = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)\r\ns.bind(('127.0.0.1', 9999))\t\t# UDP首先要绑定端口\r\nprint('Bind UDP on 9999...')\r\nwhile True:\r\n    # 接收数据:\r\n    data, addr = s.recvfrom(1024)\r\n    print('Received from %s:%s.' % addr)\r\n    s.sendto(b'Hello, %s!' % data, addr)\r\n    \r\n# 客户端\r\ns = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)\r\nfor data in [b'Michael', b'Tracy', b'Sarah']:\r\n    # 发送数据:\r\n    s.sendto(data, ('127.0.0.1', 9999))\r\n    # 接收数据:\r\n    print(s.recv(1024).decode('utf-8'))\r\ns.close()\r\n```\r\n\r\n- "}}]);